### Configure Custom Elements and Leaves in Payload CMS Rich Text Editor

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/slate.mdx

This example demonstrates how to configure a Rich Text Editor field within a Payload CMS collection, showcasing the integration of custom elements (e.g., 'cta' with a custom button and element component) and custom leaves (e.g., 'highlight' with a custom button and leaf component). It also illustrates how to extend the default link element with additional fields and configure upload elements for specific collections. This setup requires `payload` and `@payloadcms/richtext-slate`.

```ts
import type { CollectionConfig } from 'payload';

import { slateEditor } from '@payloadcms/richtext-slate';

export const ExampleCollection: CollectionConfig = {
  slug: 'example-collection',
  fields: [
    {
      name: 'content', // required
      type: 'richText', // required
      defaultValue: [
        {
          children: [{ text: 'Here is some default content for this field' }],
        },
      ],
      required: true,
      editor: slateEditor({
        admin: {
          elements: [
            'h2',
            'h3',
            'h4',
            'link',
            'blockquote',
            {
              name: 'cta',
              Button: CustomCallToActionButton,
              Element: CustomCallToActionElement,
              plugins: [
                // any plugins that are required by this element go here
              ],
            },
          ],
          leaves: [
            'bold',
            'italic',
            {
              name: 'highlight',
              Button: CustomHighlightButton,
              Leaf: CustomHighlightLeaf,
              plugins: [
                // any plugins that are required by this leaf go here
              ],
            },
          ],
          link: {
            // Inject your own fields into the Link element
            fields: [
              {
                name: 'rel',
                label: 'Rel Attribute',
                type: 'select',
                hasMany: true,
                options: ['noopener', 'noreferrer', 'nofollow'],
              },
            ],
          },
          upload: {
            collections: {
              media: {
                fields: [
                  // any fields that you would like to save
                  // on an upload element in the `media` collection
                ],
              },
            },
          },
        },
      }),
    },
  ],
};
```

